pub(super) fn dispatch(
    engine: &Lodestar,
    name: &str,
    args: &Value,
) -> Option<Result<Value, String>> {
    match name {
        "create_task" => Some((|| {
            let task = engine
                .create_task_after(
                    req_str(args, "goal_id")?,
                    req_str(args, "title")?,
                    opt_str(args, "acceptance").unwrap_or_default().as_str(),
                    optional_string_arg(args, "blocked_by")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&task)
        })()),
        "decompose_goal" => Some((|| {
            ok(&engine
                .decompose_goal(req_str(args, "goal_id")?)
                .map_err(|e| e.to_string())?)
        })()),
        "next_task" => Some((|| match engine.next_task().map_err(|e| e.to_string())? {
            Some(t) => ok(&t),
            None => text("no claimable task".to_string()),
        })()),
        "claim_task" => Some((|| {
            let won = engine
                .claim_task(
                    req_str(args, "task_id")?,
                    opt_str(args, "agent").unwrap_or_default().as_str(),
                    i64_arg(args, "lease_secs", 300),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "won": won }))
        })()),
        "renew_lease" => Some((|| {
            let renewed = engine
                .renew_lease(
                    req_str(args, "task_id")?,
                    opt_str(args, "agent").unwrap_or_default().as_str(),
                    i64_arg(args, "lease_secs", 300),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "renewed": renewed }))
        })()),
        "complete_task" => Some((|| {
            let evidence = parse_evidence(args)?;
            let (completed, conformance) = engine
                .complete_task(
                    req_str(args, "task_id")?,
                    opt_str(args, "agent").unwrap_or_default().as_str(),
                    &evidence,
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "completed": completed, "conformance": conformance }))
        })()),
        "release_task" => Some((|| {
            let released = engine
                .release_task(
                    req_str(args, "task_id")?,
                    opt_str(args, "agent").unwrap_or_default().as_str(),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "released": released }))
        })()),
        "block_task" => Some((|| {
            let blocked = engine
                .block_task(
                    req_str(args, "task_id")?,
                    optional_string_arg(args, "blocked_by")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "blocked": blocked }))
        })()),
        "reopen_task" => Some((|| {
            let reopened = engine
                .reopen_task(req_str(args, "task_id")?)
                .map_err(|e| e.to_string())?;
            ok(&json!({ "reopened": reopened }))
        })()),
        "board" => Some((|| ok(&engine.board().map_err(|e| e.to_string())?))()),
        _ => None,
    }
}

#[cfg(test)]
mod tests {
    use super::super::call;
    use super::*;
    use lodestar_core::GoalKind;

    #[test]
    fn create_task_dispatch_accepts_a_predecessor() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Handoff", "serialize edits", None)
            .unwrap();
        let first = engine.create_task(&goal.id, "First", "done").unwrap();

        let result = call(
            &engine,
            &json!({
                "name": "create_task",
                "arguments": {
                    "goal_id": goal.id,
                    "title": "Second",
                    "acceptance": "done",
                    "blocked_by": first.id
                }
            }),
        )
        .unwrap();
        let task: Value =
            serde_json::from_str(result["content"][0]["text"].as_str().unwrap()).unwrap();

        assert_eq!(task["status"], "blocked");
        assert!(task["blocked_by"].as_str().unwrap().starts_with("task:"));
    }

    #[test]
    fn reopen_task_dispatch_returns_a_manual_hold_to_open() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Recover", "unstick work", None)
            .unwrap();
        let task = engine.create_task(&goal.id, "Held", "done").unwrap();
        // A manual hold with no predecessor was previously unrecoverable via the
        // tool surface; reopen_task must return it to a claimable state.
        engine.block_task(&task.id, None).unwrap();

        let result = call(
            &engine,
            &json!({ "name": "reopen_task", "arguments": { "task_id": task.id } }),
        )
        .unwrap();
        let payload: Value =
            serde_json::from_str(result["content"][0]["text"].as_str().unwrap()).unwrap();
        assert_eq!(payload["reopened"], true);

        let board = engine.board().unwrap();
        let reopened = board.iter().find(|t| t.id == task.id).unwrap();
        assert_eq!(reopened.status.as_str(), "open");
    }

    #[test]
    fn create_task_rejects_malformed_predecessor_and_preserves_legacy_calls() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Handoff", "serialize edits", None)
            .unwrap();
        let malformed = json!({
            "name": "create_task",
            "arguments": {
                "goal_id": goal.id,
                "title": "Unsafe",
                "blocked_by": 42
            }
        });
        assert!(call(&engine, &malformed)
            .unwrap_err()
            .contains("must be a string"));

        let legacy = call(
            &engine,
            &json!({
                "name": "create_task",
                "arguments": { "goal_id": goal.id, "title": "Legacy" }
            }),
        )
        .unwrap();
        let task: Value =
            serde_json::from_str(legacy["content"][0]["text"].as_str().unwrap()).unwrap();
        assert_eq!(task["status"], "open");
        assert!(task["blocked_by"].is_null());
    }
}
